object SyncularAppOperations {
    fun newComment(input: NewComment, baseVersion: Long? = 0): SyncularGeneratedOperation {
        val payload = linkedMapOf<String, Any?>()
        payload["task_id"] = input.taskId
        input.projectId?.let { payload["project_id"] = it }
        payload["body"] = input.body
        payload["author_id"] = input.authorId
        payload["deleted"] = input.deleted ?: 0L
        return SyncularGeneratedOperation(
            table = "comments",
            rowId = input.id,
            op = SyncularGeneratedOperationKind.Upsert,
            payload = payload,
            baseVersion = baseVersion,
        )
    }

    fun patchComment(rowId: String, patch: CommentPatch, baseVersion: Long? = null): SyncularGeneratedOperation {
        val payload = linkedMapOf<String, Any?>()
        patch.taskId?.let { payload["task_id"] = it }
        patch.projectId?.let { payload["project_id"] = it }
        patch.body?.let { payload["body"] = it }
        patch.authorId?.let { payload["author_id"] = it }
        patch.deleted?.let { payload["deleted"] = it }
        return SyncularGeneratedOperation(
            table = "comments",
            rowId = rowId,
            op = SyncularGeneratedOperationKind.Upsert,
            payload = payload,
            baseVersion = baseVersion,
        )
    }

    fun deleteComment(rowId: String, baseVersion: Long? = null): SyncularGeneratedOperation = SyncularGeneratedOperation(
        table = "comments",
        rowId = rowId,
        op = SyncularGeneratedOperationKind.Upsert,
        payload = linkedMapOf("deleted" to 1L),
        baseVersion = baseVersion,
    )

    fun newProject(input: NewProject, baseVersion: Long? = 0): SyncularGeneratedOperation {
        val payload = linkedMapOf<String, Any?>()
        payload["name"] = input.name
        payload["owner_id"] = input.ownerId
        payload["archived"] = input.archived ?: 0L
        return SyncularGeneratedOperation(
            table = "projects",
            rowId = input.id,
            op = SyncularGeneratedOperationKind.Upsert,
            payload = payload,
            baseVersion = baseVersion,
        )
    }

    fun patchProject(rowId: String, patch: ProjectPatch, baseVersion: Long? = null): SyncularGeneratedOperation {
        val payload = linkedMapOf<String, Any?>()
        patch.name?.let { payload["name"] = it }
        patch.ownerId?.let { payload["owner_id"] = it }
        patch.archived?.let { payload["archived"] = it }
        return SyncularGeneratedOperation(
            table = "projects",
            rowId = rowId,
            op = SyncularGeneratedOperationKind.Upsert,
            payload = payload,
            baseVersion = baseVersion,
        )
    }

    fun deleteProject(rowId: String, baseVersion: Long? = null): SyncularGeneratedOperation = SyncularGeneratedOperation(
        table = "projects",
        rowId = rowId,
        op = SyncularGeneratedOperationKind.Delete,
        payload = null,
        baseVersion = baseVersion,
    )

    fun newTask(input: NewTask, baseVersion: Long? = 0): SyncularGeneratedOperation {
        val payload = linkedMapOf<String, Any?>()
        payload["title"] = input.title
        payload["completed"] = input.completed ?: 0L
        payload["user_id"] = input.userId
        input.projectId?.let { payload["project_id"] = it }
        input.image?.let { payload["image"] = it.toJsonValue() }
        input.titleYjsState?.let { payload["title_yjs_state"] = it }
        return SyncularGeneratedOperation(
            table = "tasks",
            rowId = input.id,
            op = SyncularGeneratedOperationKind.Upsert,
